import{_ as s,o as t,c as n,ai as o}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Presence","description":"","frontmatter":{"summary":"How OpenSoul presence entries are produced, merged, and displayed","read_when":["Debugging the Instances tab","Investigating duplicate or stale instance rows","Changing gateway WS connect or system-event beacons"],"title":"Presence"},"headers":[],"relativePath":"concepts/presence.md","filePath":"concepts/presence.md","lastUpdated":null}'),a={name:"concepts/presence.md"};function c(d,e,r,i,l,h){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="presence" tabindex="-1"><a class="header-anchor" href="#presence">#</a> Presence</h1><p>OpenSoul “presence” is a lightweight, best‑effort view of:</p><ul><li>the <strong>Gateway</strong> itself, and</li><li><strong>clients connected to the Gateway</strong> (mac app, WebChat, CLI, etc.)</li></ul><p>Presence is used primarily to render the macOS app’s <strong>Instances</strong> tab and to provide quick operator visibility.</p><h2 id="presence-fields-what-shows-up" tabindex="-1"><a class="header-anchor" href="#presence-fields-what-shows-up">#</a> Presence fields (what shows up)</h2><p>Presence entries are structured objects with fields like:</p><ul><li><code>instanceId</code> (optional but strongly recommended): stable client identity (usually <code>connect.client.instanceId</code>)</li><li><code>host</code>: human‑friendly host name</li><li><code>ip</code>: best‑effort IP address</li><li><code>version</code>: client version string</li><li><code>deviceFamily</code> / <code>modelIdentifier</code>: hardware hints</li><li><code>mode</code>: <code>ui</code>, <code>webchat</code>, <code>cli</code>, <code>backend</code>, <code>probe</code>, <code>test</code>, <code>node</code>, ...</li><li><code>lastInputSeconds</code>: “seconds since last user input” (if known)</li><li><code>reason</code>: <code>self</code>, <code>connect</code>, <code>node-connected</code>, <code>periodic</code>, ...</li><li><code>ts</code>: last update timestamp (ms since epoch)</li></ul><h2 id="producers-where-presence-comes-from" tabindex="-1"><a class="header-anchor" href="#producers-where-presence-comes-from">#</a> Producers (where presence comes from)</h2><p>Presence entries are produced by multiple sources and <strong>merged</strong>.</p><h3 id="_1-gateway-self-entry" tabindex="-1"><a class="header-anchor" href="#_1-gateway-self-entry">#</a> 1) Gateway self entry</h3><p>The Gateway always seeds a “self” entry at startup so UIs show the gateway host even before any clients connect.</p><h3 id="_2-websocket-connect" tabindex="-1"><a class="header-anchor" href="#_2-websocket-connect">#</a> 2) WebSocket connect</h3><p>Every WS client begins with a <code>connect</code> request. On successful handshake the Gateway upserts a presence entry for that connection.</p><h4 id="why-one‐off-cli-commands-don-t-show-up" tabindex="-1"><a class="header-anchor" href="#why-one‐off-cli-commands-don-t-show-up">#</a> Why one‑off CLI commands don’t show up</h4><p>The CLI often connects for short, one‑off commands. To avoid spamming the Instances list, <code>client.mode === &quot;cli&quot;</code> is <strong>not</strong> turned into a presence entry.</p><h3 id="_3-system-event-beacons" tabindex="-1"><a class="header-anchor" href="#_3-system-event-beacons">#</a> 3) <code>system-event</code> beacons</h3><p>Clients can send richer periodic beacons via the <code>system-event</code> method. The mac app uses this to report host name, IP, and <code>lastInputSeconds</code>.</p><h3 id="_4-node-connects-role-node" tabindex="-1"><a class="header-anchor" href="#_4-node-connects-role-node">#</a> 4) Node connects (role: node)</h3><p>When a node connects over the Gateway WebSocket with <code>role: node</code>, the Gateway upserts a presence entry for that node (same flow as other WS clients).</p><h2 id="merge-dedupe-rules-why-instanceid-matters" tabindex="-1"><a class="header-anchor" href="#merge-dedupe-rules-why-instanceid-matters">#</a> Merge + dedupe rules (why <code>instanceId</code> matters)</h2><p>Presence entries are stored in a single in‑memory map:</p><ul><li>Entries are keyed by a <strong>presence key</strong>.</li><li>The best key is a stable <code>instanceId</code> (from <code>connect.client.instanceId</code>) that survives restarts.</li><li>Keys are case‑insensitive.</li></ul><p>If a client reconnects without a stable <code>instanceId</code>, it may show up as a <strong>duplicate</strong> row.</p><h2 id="ttl-and-bounded-size" tabindex="-1"><a class="header-anchor" href="#ttl-and-bounded-size">#</a> TTL and bounded size</h2><p>Presence is intentionally ephemeral:</p><ul><li><strong>TTL:</strong> entries older than 5 minutes are pruned</li><li><strong>Max entries:</strong> 200 (oldest dropped first)</li></ul><p>This keeps the list fresh and avoids unbounded memory growth.</p><h2 id="remote-tunnel-caveat-loopback-ips" tabindex="-1"><a class="header-anchor" href="#remote-tunnel-caveat-loopback-ips">#</a> Remote/tunnel caveat (loopback IPs)</h2><p>When a client connects over an SSH tunnel / local port forward, the Gateway may see the remote address as <code>127.0.0.1</code>. To avoid overwriting a good client‑reported IP, loopback remote addresses are ignored.</p><h2 id="consumers" tabindex="-1"><a class="header-anchor" href="#consumers">#</a> Consumers</h2><h3 id="macos-instances-tab" tabindex="-1"><a class="header-anchor" href="#macos-instances-tab">#</a> macOS Instances tab</h3><p>The macOS app renders the output of <code>system-presence</code> and applies a small status indicator (Active/Idle/Stale) based on the age of the last update.</p><h2 id="debugging-tips" tabindex="-1"><a class="header-anchor" href="#debugging-tips">#</a> Debugging tips</h2><ul><li>To see the raw list, call <code>system-presence</code> against the Gateway.</li><li>If you see duplicates: <ul><li>confirm clients send a stable <code>client.instanceId</code> in the handshake</li><li>confirm periodic beacons use the same <code>instanceId</code></li><li>check whether the connection‑derived entry is missing <code>instanceId</code> (duplicates are expected)</li></ul></li></ul>',34)])])}const m=s(a,[["render",c]]);export{u as __pageData,m as default};
